def merge_env(base, env_overrides, cli_overrides):
    return {**base, **env_overrides, **cli_overrides}

base = {'debug': False, 'port': 8000, 'workers': 4}
env = {'debug': True, 'port': 9000}
cli = {'port': 3000}
result = merge_env(base, env, cli)
print(result)
print(base)
